<div class="group relative w-full border-y border-slate-100 bg-slate-50/50 py-4 transition-colors duration-300 dark:border-white/5 dark:bg-white/[0.02]">
    <div class="mx-auto max-w-7xl px-4 sm:px-6 lg:px-8">
        <div class="relative w-full overflow-hidden py-10 sm:py-12 [mask-image:linear-gradient(to_right,transparent_0,black_10%,black_90%,transparent_100%)]" dir="ltr">
            <div class="track flex w-fit items-center">
                {#each [technologies, technologies] as set}
                    <div class="flex shrink-0 items-center gap-16 pr-16 sm:gap-24 sm:pr-24">
                        {#each set as tech}
                            <div 
                                class="marquee-item flex shrink-0 items-center gap-4 cursor-pointer"
                                style="--brand-color: {tech.brandColor}"
                                data-slug={tech.slug}
                            >
                                <svg role="img" viewBox="0 0 24 24" class="h-12 w-12 sm:h-14 sm:w-14" fill="currentColor">
                                    <title>{tech.name}</title>
                                    <path d={tech.path} />
                                </svg>
                                <span class="whitespace-nowrap text-base font-bold text-slate-400 transition-colors duration-300 group-hover:text-slate-200 dark:group-hover:text-slate-400 sm:text-lg label-text">{tech.name}</span>
                            </div>
                        {/each}
                    </div>
                {/each}
            </div>
        </div>
    </div>
</div>

<style>
    @keyframes mq {
        0% { transform: translateX(0); }
        100% { transform: translateX(-50%); }
    }
    .track {
        animation: mq 30s linear infinite;
    }
    .group:hover .track {
        animation-play-state: paused;
    }
    
    .marquee-item {
        color: var(--color-slate-400);
        opacity: 0.6;
        transition: color 0.4s cubic-bezier(0.16, 1, 0.3, 1), opacity 0.4s ease, transform 0.4s cubic-bezier(0.16, 1, 0.3, 1);
    }
    
    .group:hover .marquee-item {
        opacity: 0.45;
    }
    
    .marquee-item:hover {
        color: var(--brand-color);
        opacity: 1 !important;
        transform: scale(1.15);
    }

    .marquee-item:hover .label-text {
        color: #0f172a;
    }

    :global(.dark) .marquee-item:hover .label-text {
        color: #f1f5f9;
    }

    /* Next.js and OpenAI brand colors dark mode overrides */
    :global(.dark) .marquee-item[data-slug="nextdotjs"]:hover,
    :global(.dark) .marquee-item[data-slug="openai"]:hover {
        color: #ffffff !important;
    }

    /* Next.js and OpenAI brand colors light mode overrides */
    .marquee-item[data-slug="nextdotjs"]:hover,
    .marquee-item[data-slug="openai"]:hover {
        color: #0f172a;
    }
</style>
